import { NextResponse } from "next/server"
import { pool } from "@/lib/server/db"

export const runtime = "nodejs"

type RouteStatus = "pendiente" | "en_proceso" | "completado"

type RouteStopResponse = {
  id: number
  cliente: string
  ubicacion: string
  notas: string
  estatus: "Pendiente" | "Listo" | "Cerrado" | "Material Estorbando" | "Notas"
  evidencia1: string | null
  evidencia2: string | null
  evidencia3: string | null
  evidencia4: string | null
  evidencia5: string | null
  firma: string | null
  hora_firma: string | null
}

function toUiStatus(estatus: RouteStatus) {
  switch (estatus) {
    case "completado":
      return "Listo"
    case "pendiente":
      return "Pendiente"
    default:
      return "Notas"
  }
}

export async function GET() {
  const registrosCountResult = await pool.query<{ total: string }>(
    "SELECT COUNT(*)::text AS total FROM renta.registros_ruta"
  )

  if (Number(registrosCountResult.rows[0]?.total ?? "0") === 0) {
    await pool.query(
      `
        INSERT INTO renta.registros_ruta
          (
            id,
            orden_id,
            cliente,
            ubicacion,
            notas,
            estatus,
            ruta,
            dia,
            fecha
          )
        SELECT
          COALESCE((SELECT MAX(id) FROM renta.registros_ruta), 0) + ROW_NUMBER() OVER (ORDER BY o.id) AS id,
          o.id AS orden_id,
          o.cliente_nombre AS cliente,
          o.domicilio AS ubicacion,
          COALESCE(o.notas, '') AS notas,
          CASE
            WHEN o.estado = 'terminado' THEN 'completado'::renta.estatus_ruta
            WHEN o.estado = 'cancelado' THEN 'en_proceso'::renta.estatus_ruta
            ELSE 'pendiente'::renta.estatus_ruta
          END AS estatus,
          o.ruta,
          CASE
            WHEN LOWER(COALESCE(o.frecuencia, '')) LIKE '%lunes%' THEN 'Lunes'
            WHEN LOWER(COALESCE(o.frecuencia, '')) LIKE '%martes%' THEN 'Martes'
            WHEN LOWER(COALESCE(o.frecuencia, '')) LIKE '%miercoles%' THEN 'Miercoles'
            WHEN LOWER(COALESCE(o.frecuencia, '')) LIKE '%miércoles%' THEN 'Miercoles'
            WHEN LOWER(COALESCE(o.frecuencia, '')) LIKE '%jueves%' THEN 'Jueves'
            WHEN LOWER(COALESCE(o.frecuencia, '')) LIKE '%viernes%' THEN 'Viernes'
            WHEN LOWER(COALESCE(o.frecuencia, '')) LIKE '%sabado%' THEN 'Sabado'
            WHEN LOWER(COALESCE(o.frecuencia, '')) LIKE '%sábado%' THEN 'Sabado'
            WHEN LOWER(COALESCE(o.frecuencia, '')) LIKE '%domingo%' THEN 'Domingo'
            ELSE 'Lunes'
          END AS dia,
          CURRENT_DATE AS fecha
        FROM renta.ordenes o
      `
    )
  }

  const [clientsResult, routesResult] = await Promise.all([
    pool.query<{
      id: number
      nombre: string
      empresa: string
      telefono: string | null
      email: string | null
      domicilio: string
    }>(
      `
        SELECT id, nombre, empresa, telefono, email, domicilio
        FROM renta.clientes
        ORDER BY id ASC
      `
    ),
    pool.query<{
      id: number
      cliente: string
      ubicacion: string
      notas: string
      estatus: RouteStatus
      evidencia1: string | null
      evidencia2: string | null
      evidencia3: string | null
      evidencia4: string | null
      evidencia5: string | null
      firma: string | null
      hora_firma: string | null
      ruta: number
      dia: string
    }>(
      `
        SELECT
          id,
          cliente,
          ubicacion,
          notas,
          estatus,
          evidencia1,
          evidencia2,
          evidencia3,
          evidencia4,
          evidencia5,
          firma,
          TO_CHAR(hora_firma, 'HH24:MI') AS hora_firma,
          ruta,
          dia
        FROM renta.registros_ruta
        ORDER BY ruta ASC, dia ASC, id ASC
      `
    ),
  ])

  const clients = clientsResult.rows.map((row) => ({
    id: row.id,
    nombre: row.nombre,
    empresa: row.empresa,
    telefono: row.telefono ?? "",
    email: row.email ?? "",
    direccion: row.domicilio,
    activo: true,
  }))

  const routes: Record<string, Record<string, RouteStopResponse[]>> = {}
  for (const row of routesResult.rows) {
    const routeKey = String(row.ruta)
    if (!routes[routeKey]) {
      routes[routeKey] = {}
    }
    if (!routes[routeKey][row.dia]) {
      routes[routeKey][row.dia] = []
    }

    routes[routeKey][row.dia].push({
      id: row.id,
      cliente: row.cliente,
      ubicacion: row.ubicacion,
      notas: row.notas ?? "",
      estatus: toUiStatus(row.estatus),
      evidencia1: row.evidencia1,
      evidencia2: row.evidencia2,
      evidencia3: row.evidencia3,
      evidencia4: row.evidencia4,
      evidencia5: row.evidencia5,
      firma: row.firma,
      hora_firma: row.hora_firma,
    })
  }

  return NextResponse.json({ clients, routes })
}
